public class StringBuilderExample {
 public static void main(String[] args) {
 StringBuilder sb = new StringBuilder();
 sb.append("Hello");
 sb.append(" World");
 System.out.println(sb.toString());
 }
}

public class StringBuilderMethodsExample {
 public static void main(String[] args) {
 StringBuilder sb = new StringBuilder();
 sb.append("Hello");
 sb.insert(5, " World");
 sb.delete(0, 5);
 sb.reverse();
 System.out.println(sb.toString());
 }
}
